define(['core/ajax','core/log','block_mwa_dashboard/dashboardstore','block_mwa_dashboard/dashboardapp'],function(Ajax,Log,Store,DashboardApp){'use strict';var callAction=function(method,args){var calls=Ajax.call([{methodname:method,args:args||{}}]);return calls[0];};var deliverError=function(err){var dashboard=Store.getModule('MWADashboard');var message=(err&&err.message)?err.message:String(err||'Data load failed');if(dashboard&&typeof dashboard.receiveError==='function'){dashboard.receiveError(message);}};var loadAndDeliver=function(courseid){var calls=Ajax.call([{methodname:'block_mwa_dashboard_get_logs',args:{courseid:courseid,since:0}},{methodname:'block_mwa_dashboard_get_grades',args:{courseid:courseid}}]);return Promise.all([calls[0],calls[1]]).then(function(results){var dashboard=Store.getModule('MWADashboard');var logsResult=results[0];var gradesResult=results[1];if(dashboard&&typeof dashboard.receiveData==='function'){dashboard.receiveData({type:'mwa-data',logs:logsResult.logs||'[]',logsCount:logsResult.count||0,grades:gradesResult.grades||'[]',gradesCount:gradesResult.count||0});}return results;}).catch(function(err){Log.error('block_mwa_dashboard/dashboard:data load failed');Log.error(err);deliverError(err);});};var init=function(params){Log.debug('block_mwa_dashboard/dashboard:init');params=params||{};var config=params.config||{};var courseid=params.courseid?parseInt(params.courseid,10):parseInt(config.courseid||0,10);Store.configure(config,params.strings||{},callAction);DashboardApp.init(config);if(courseid>0){loadAndDeliver(courseid);}};return{init:init};});
